"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[30],{104(e,o,t){t.r(o),t.d(o,{assets:()=>h,contentTitle:()=>i,default:()=>u,frontMatter:()=>r,metadata:()=>a,toc:()=>d});const a=JSON.parse('{"id":"stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-9","title":"Discourses \u2014 Book 1, Chapter 9","description":"Book 1 \u2014 Chapter 9","source":"@site/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-9.md","sourceDirName":"stoicism/epictetus/discourses/book-1","slug":"/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-9","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-9","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":10,"frontMatter":{"sidebar_position":10,"title":"Discourses \u2014 Book 1, Chapter 9","sidebar_label":"Book 1, Ch. 9"},"sidebar":"philosophersSidebar","previous":{"title":"Book 1, Ch. 8","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-8"},"next":{"title":"Book 1, Ch. 10","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-10"}}');var s=t(4848),n=t(8453);const r={sidebar_position:10,title:"Discourses \u2014 Book 1, Chapter 9",sidebar_label:"Book 1, Ch. 9"},i="Discourses",h={},d=[{value:"Book 1 \u2014 Chapter 9",id:"book-1--chapter-9",level:2},{value:"How One May Draw Conclusions From The Fact That We Are God&#39;S Kinsmen",id:"how-one-may-draw-conclusions-from-the-fact-that-we-are-gods-kinsmen",level:3},{value:"Sonnet 4.6 Summary",id:"sonnet-46-summary",level:2},{value:"Text",id:"text",level:2}];function l(e){const o={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",...(0,n.R)(),...e.components},{Details:t}=o;return t||function(e,o){throw new Error("Expected "+(o?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,s.jsxs)(s.Fragment,{children:[(0,s.jsxs)("div",{style:{textAlign:"center"},children:[(0,s.jsx)(o.header,{children:(0,s.jsx)(o.h1,{id:"discourses",children:"Discourses"})}),(0,s.jsx)(o.h2,{id:"book-1--chapter-9",children:"Book 1 \u2014 Chapter 9"}),(0,s.jsx)(o.h3,{id:"how-one-may-draw-conclusions-from-the-fact-that-we-are-gods-kinsmen",children:"How One May Draw Conclusions From The Fact That We Are God'S Kinsmen"})]}),"\n",(0,s.jsx)(o.p,{children:(0,s.jsx)(o.em,{children:"Translated by P.E. Matheson (Oxford: Clarendon Press, 1916)"})}),"\n",(0,s.jsxs)(t,{open:!0,children:[(0,s.jsx)("summary",{children:"Sonnet 4.6 Summary"}),(0,s.jsx)(o.h2,{id:"sonnet-46-summary",children:"Sonnet 4.6 Summary"}),(0,s.jsx)(o.p,{children:"Extends the theme of Ch. 3 with more practical and political weight. If we truly share in God's rational nature, then national identity is a kind of smallness \u2014 Socrates was right to call himself a citizen of the universe rather than of Athens. Our true homeland is the whole rational order."}),(0,s.jsx)(o.p,{children:"The political implication: kinship with Caesar gives a Roman security and freedom from fear. How much more should kinship with God do the same? Yet people grovel, flatter, and tremble before powerful men \u2014 which Epictetus reads as a failure to grasp what they actually are."}),(0,s.jsx)(o.p,{children:"He also addresses the opposite error: young men who, grasping their divine kinship, want to abandon the body entirely and \"depart to the gods.\" The answer is: wait for God's signal. You're stationed here for now \u2014 serve the post. The door is always open if things become truly unbearable, but don't leave without reason."}),(0,s.jsx)(o.p,{children:"The chapter closes with a telling anecdote: a man who lost his fortune asks Epictetus to write on his behalf in a humble, pitying tone. The man objects \u2014 he wanted help, not pity. The point: a man who still has his rational will intact has everything. Writing for him as though he's reduced to his material losses is treating a living man as a corpse."})]}),"\n",(0,s.jsxs)(t,{open:!0,children:[(0,s.jsx)("summary",{children:"Text"}),(0,s.jsx)(o.h2,{id:"text",children:"Text"}),(0,s.jsx)(o.p,{children:"IF THESE statements of the philosophers are true, that God and men are akin, there is but one course open to men, to do as Socrates did: never to reply to one who asks his country, 'I am an Athenian', or 'I am a Corinthian', but 'I am a citizen of the universe.' For why do you say that you are an Athenian, instead of merely a native of the little spot on"}),(0,s.jsx)(o.p,{children:"which your bit of a body was cast forth at birth? Plainly you call yourself Athenian or Corinthian after that more sovereign region which includes not only the very spot where you were born, and all your household, but also generally that region from which the race of your forbears has come down to you. When a man therefore has learnt to understand the government of the universe and has realized that there is nothing so great or sovereign or all-inclusive as this frame of things wherein men and God are united, and that from it come the seeds from which are sprung not only my own father or grandfather, but all things that are begotten and that grow upon earth, and rational creatures in particular --for these alone are by nature fitted to share in the society of God, being connected with Him by the bond of reason--why should he not call himself a citizen of the universe and a son of God? Why should he fear anything that can happen to him among men? When kinship with Caesar or any other of those who are powerful in Rome is sufficient to make men live in security, above all scorn and free from every fear, shall not the fact that we have God as maker and father and kinsman relieve us from pains and fears?"}),(0,s.jsx)(o.p,{children:"'And where am I to find food to eat, if I have nothing?' says one."}),(0,s.jsx)(o.p,{children:"Well, what do slaves do when they leave their masters, or what do they rely on? Do they rely on fields, or servants, or silver plate? No, on nothing but themselves; nevertheless sustenance does not fail them. And shall our philosopher in his wanderings have to rest his confidence in others, instead of taking care of himself? Is he to be baser and more cowardly than the unreasoning beasts? For each one of them is content with itself, and lacks not its proper sustenance nor the way of life that is naturally suited to it."}),(0,s.jsx)(o.p,{children:"I think that the old man who sits here to teach you ought to devote his skill not to save you from being low-minded, and from reasoning about yourselves in a low and ignoble spirit, but rather to prevent young men from arising of the type who, discovering their kinship with the gods, and seeing that we have these fetters attached to us in the shape of the body and its possessions and all that we find necessary for the course and management of our life by reason of the body, may desire to fling all these away as vexatious and useless burdens and so depart to the gods their kindred."}),(0,s.jsx)(o.p,{children:"And so your teacher and instructor, if he were a true teacher, should engage in this conflict of argument:"}),(0,s.jsx)(o.p,{children:"You come saying, 'Epictetus, we can bear no longer to be bound with the fetters of this wretched body, giving it meat and drink and rest and purgation, and by reason of the body having to adapt ourselves to this or that set of circumstances. Are not these things indifferent and as nothing to us, and death no evil thing? Are we not kinsmen of the gods,"}),(0,s.jsx)(o.p,{children:"from whom we have come hither? Suffer us to depart to the place whence we have come, suffer us to be released from these bonds that are fastened to us and weigh us down. Here are robbers and thieves and law-courts and so-called kings, who by reason of our poor body and its possessions are accounted to have authority over us. Suffer us to show them that they have authority over nothing.'"}),(0,s.jsx)(o.p,{children:"Hereupon I answer: 'Men as you are, wait upon God. When He gives the signal and releases you from this service, then you shall depart to Him; but for the present be content to dwell in this country wherein He appointed you to dwell. Short indeed is the time of your dwelling here, and easy for them whose spirit is thus disposed. What manner of tyrant or what thief or what law-courts have any fears for those who have thus set at nought the body and its possessions? Stay where you are, and depart not without reason.' Such should be the answer of the teacher to his gifted pupils. How different is what we see! There is no life in your master, and no life in you. When you have had your fill to-day, you sit groaning about the morrow, and how you are to find food. Slave, if you get food, you will have it; if not, you will depart: the door is open. Why do you whine? What room is there for tears any more? What occasion for flattery any more? Why should one envy another? Why should he gaze with wonder on them that are rich or powerful, especially if they be strong and quick to anger? For what will they do with us? We will pay no heed to what they have power to do, what we really care for they cannot touch. Who, I ask you, will be master over one who is of this spirit?"}),(0,s.jsx)(o.p,{children:"How did Socrates approach these matters? Surely as one should who is convinced of his kinship with the gods. 'If you tell me,' he says, '\"We; acquit you on condition that you discourse no longer as you have done hitherto, and that you do not annoy young or old among us\"', I shall answer, 'It is absurd for you to suppose that, while I am bound to maintain and guard any post to which your general appointed me, and should rather die ten thousand times than abandon it, yet if God has appointed us to a certain place and way of life we ought to abandon that.' [Plato, Apology, 29c, 28e] Here you see a man who is a kinsman of the gods in very truth. But as for us--we think of ourselves as if we were all belly and flesh and animal desire; such are our fears, such our passions; those that can help us to these ends we flatter, and at the same time fear."}),(0,s.jsx)(o.p,{children:"Some one has asked me to write for him to Rome, one who, as the world thought, had had misfortunes; he had once been famous and rich, and had now lost everything and was living here. So I wrote for him in a humble tone. And he read my letter and gave it me back and said, 'I wanted your help, not your pity.' So, too, Rufus, to try me, used to say,"}),(0,s.jsx)(o.p,{children:"[paragraph continues] 'Your master will do this or that to you'; and when I answered him, 'This is the lot of man', 'Why then', said he, 'do I appeal to your master when I can get everything from you?' for, indeed, it is true that what a man has of himself it is idle and futile for him to receive from another. Am I then, who can get from myself the gift of a noble and lofty spirit, to get from you a field or money or office? Heaven forbid! I will not be so blind to my true possessions. But when a man is mean and cowardly, for him one must needs write letters as for one that is dead. 'Make us a present of the corpse of so and so and his miserable quart of blood.' For indeed such a one is a mere corpse and a quart of blood and nothing more. If he were anything more, he would have realized that one man cannot make another miserable."})]})]})}function u(e={}){const{wrapper:o}={...(0,n.R)(),...e.components};return o?(0,s.jsx)(o,{...e,children:(0,s.jsx)(l,{...e})}):l(e)}},8453(e,o,t){t.d(o,{R:()=>r,x:()=>i});var a=t(6540);const s={},n=a.createContext(s);function r(e){const o=a.useContext(n);return a.useMemo(function(){return"function"==typeof e?e(o):{...o,...e}},[o,e])}function i(e){let o;return o=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:r(e.components),a.createElement(n.Provider,{value:o},e.children)}}}]);